#[no_mangle]
pub fn fake_main() {
    unsafe {
        asm!("add sp, sp, {}", in(reg) KERNEL_SPACE_OFFSET << 12);
        asm!("la t0, rust_main");
        asm!("add t0, t0, {}", in(reg) KERNEL_SPACE_OFFSET << 12);
        asm!("jalr zero, 0(t0)");
    }
}

#[no_mangle]
/// the rust entry-point of os
pub fn rust_main() -> ! {
    #[cfg(feature = "visionfive2")]
    // sleep 5 seconds to wait for the test program to connect
    sleep_ms(5000);
    println!("Hello, world!\n");
    show_logo();
    clear_bss();
    println!("[kernel] Hello, world!");
    logging::init();
    info!("logging init done");
    let satp = satp::read();
    info!(" satp: {:#x}", satp.bits());
    #[cfg(feature = "visionfive2")]
    init_dtb(None);
    #[cfg(feature = "qemu")]
    init_dtb(None);
    let machine_info = machine_info();
    #[cfg(feature = "visionfive2")]
    mm::init(machine_info.memory.end);
    #[cfg(feature = "qemu")]
    mm::init(MEMORY_END);
    info!("mm init done");
    mm::remap_test();
    info!("mm remap test done");
    trap::init();
    info!("trap init done");
    trap::enable_timer_interrupt();
    info!("timer interrupt enabled");
    timer::set_next_trigger();
    info!("timer set next trigger done");
    // for file in ALL_TASKS.iter() {
    //     task::add_file(file);
    //     task::run_tasks();
    // }
    info!("init file system");
    fs::init();
    info!("adding initproc");
    task::add_initproc();
    info!("running tasks");
    task::run_tasks();
    println!("[kernel] All tasks finished successfully!");
    println!("[kernel] ChaOS is shutting down...");
    shutdown();
}

unsafe fn vf2_debug_print(s: &str) {
    const SBI_CONSOLE_PUTCHAR: usize = 1;

    for &c in s.as_bytes() {
        asm!(
            "li a7, 1",
            "li a6, 0",
            "ecall",
            in("a0") c as usize,
            out("a7") _,
            out("a6") _,
        );
    }
}

//! Memory management implementation
//!
//! SV39 page-based virtual-memory architecture for RV64 systems, and
//! everything about memory management, like frame allocator, page table,
//! map area and memory set, is implemented here.
//!
//! Every task or process has a memory_set to control its virtual memory.

mod address;
mod config;
mod frame_allocator;
mod heap_allocator;
mod memory_set;
mod page_table;

use address::VPNRange;
pub use address::{KernelAddr, PhysAddr, PhysPageNum, StepByOne, VirtAddr, VirtPageNum};
pub use frame_allocator::{frame_alloc, frame_alloc_contiguous, frame_dealloc, FrameTracker};
pub use heap_allocator::init_heap;
pub use memory_set::{kernel_token, remap_test, MapPermission, MemorySet, KERNEL_SPACE};
pub use page_table::{
    translated_byte_buffer,
    translated_ref,
    translated_refmut,
    translated_str,
    PTEFlags,
    PageTable,
    PageTableEntry,
    UserBuffer,
    UserBufferIterator,
};

/// initiate heap allocator, frame allocator and kernel space
pub fn init(memory_end: usize) {
    debug!("heap allocator initialize");
    heap_allocator::init_heap();
    debug!("frame allocator initialize");
    frame_allocator::init_frame_allocator(memory_end);
    debug!("kernel space initialize");
    KERNEL_SPACE.exclusive_access(file!(), line!()).activate();
}

//! PhysAddr, VirtAddr, PhysPageNum, VirtPageNum, raw address

use core::fmt::{self, Debug, Formatter};

use super::PageTableEntry;
use crate::config::{KERNEL_SPACE_OFFSET, PAGE_SIZE, PAGE_SIZE_BITS, PAGE_TABLE_LEVEL};

const PA_WIDTH_SV39: usize = 56;
const VA_WIDTH_SV39: usize = 39;
const PPN_WIDTH_SV39: usize = PA_WIDTH_SV39 - PAGE_SIZE_BITS;
const VPN_WIDTH_SV39: usize = VA_WIDTH_SV39 - PAGE_SIZE_BITS;

/// Physical Address
#[repr(C)]
#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct PhysAddr(pub usize);

/// Virtual Address
#[repr(C)]
#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct VirtAddr(pub usize);

/// Physical Page Number PPN
#[repr(C)]
#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct PhysPageNum(pub usize);

/// Virtual Page Number VPN
#[repr(C)]
#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct VirtPageNum(pub usize);

/// kernel address
#[repr(C)]
#[derive(Copy, Clone, Ord, PartialOrd, Eq, PartialEq)]
pub struct KernelAddr(pub usize);

/// Debugging

impl Debug for VirtAddr {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("VA:{:#x}", self.0))
    }
}
impl Debug for VirtPageNum {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("VPN:{:#x}", self.0))
    }
}
impl Debug for PhysAddr {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("PA:{:#x}", self.0))
    }
}
impl Debug for PhysPageNum {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        f.write_fmt(format_args!("PPN:{:#x}", self.0))
    }
}

/// T: {PhysAddr, VirtAddr, PhysPageNum, VirtPageNum}
/// T -> usize: T.0
/// usize -> T: usize.into()

impl From<usize> for KernelAddr {
    fn from(v: usize) -> Self {
        Self(v)
    }
}
impl From<PhysAddr> for KernelAddr {
    fn from(pa: PhysAddr) -> Self {
        Self(pa.0 + (KERNEL_SPACE_OFFSET << PAGE_SIZE_BITS))
    }
}

impl From<KernelAddr> for PhysAddr {
    fn from(ka: KernelAddr) -> Self {
        Self(ka.0 - (KERNEL_SPACE_OFFSET << PAGE_SIZE_BITS))
    }
}

impl From<KernelAddr> for VirtAddr {
    fn from(ka: KernelAddr) -> Self {
        Self(ka.0)
    }
}

impl From<usize> for PhysAddr {
    fn from(v: usize) -> Self {
        // Self(v & ((1 << PA_WIDTH_SV39) - 1))
        let tmp = (v as isize >> PA_WIDTH_SV39) as isize;
        assert!(tmp == 0 || tmp == -1);
        Self(v)
    }
}
impl From<usize> for PhysPageNum {
    fn from(v: usize) -> Self {
        // Self(v & ((1 << PPN_WIDTH_SV39) - 1))
        let tmp = (v as isize >> PPN_WIDTH_SV39) as isize;
        assert!(tmp == 0 || tmp == -1);
        Self(v)
    }
}
impl From<KernelAddr> for PhysPageNum {
    fn from(ka: KernelAddr) -> Self {
        let pa = PhysAddr::from(ka);
        pa.floor()
    }
}
impl From<usize> for VirtAddr {
    fn from(v: usize) -> Self {
        // Self(v & ((1 << VA_WIDTH_SV39) - 1))
        let tmp = (v as isize >> VA_WIDTH_SV39) as isize;
        // 检查传入地址是否合法（SV39标准
        assert!(tmp == 0 || tmp == -1, "invalid va: {:#x}", v);
        Self(v)
    }
}
impl From<usize> for VirtPageNum {
    fn from(v: usize) -> Self {
        // Self(v & ((1 << VPN_WIDTH_SV39) - 1))
        let tmp = v >> (VPN_WIDTH_SV39 - 1);
        // 检查传入页号是否合法（SV39标准
        assert!(
            tmp == 0 || tmp == (1 << (52 - VPN_WIDTH_SV39 + 1)) - 1,
            "Assertion failed: tmp = {:#x}",
            tmp
        );
        Self(v)
    }
}

impl From<PhysAddr> for usize {
    fn from(v: PhysAddr) -> Self {
        v.0
    }
}
impl From<PhysPageNum> for usize {
    fn from(v: PhysPageNum) -> Self {
        v.0
    }
}
impl From<VirtAddr> for usize {
    fn from(v: VirtAddr) -> Self {
        if v.0 >= (1 << (VA_WIDTH_SV39 - 1)) {
            v.0 | (!((1 << VA_WIDTH_SV39) - 1))
        } else {
            v.0
        }
    }
}
impl From<VirtPageNum> for usize {
    fn from(v: VirtPageNum) -> Self {
        v.0
    }
}

impl VirtAddr {
    /// Get the (floor) virtual page number
    pub fn floor(&self) -> VirtPageNum {
        VirtPageNum(self.0 / PAGE_SIZE)
    }

    /// Get the (ceil) virtual page number
    pub fn ceil(&self) -> VirtPageNum {
        VirtPageNum((self.0 - 1 + PAGE_SIZE) / PAGE_SIZE)
    }

    /// Get the page offset of virtual address
    pub fn page_offset(&self) -> usize {
        self.0 & (PAGE_SIZE - 1)
    }

    /// Check if the virtual address is aligned by page size
    pub fn aligned(&self) -> bool {
        self.page_offset() == 0
    }
}
impl From<VirtAddr> for VirtPageNum {
    fn from(v: VirtAddr) -> Self {
        assert_eq!(v.page_offset(), 0);
        v.floor()
    }
}
impl From<VirtPageNum> for VirtAddr {
    fn from(v: VirtPageNum) -> Self {
        Self(v.0 << PAGE_SIZE_BITS)
    }
}
impl PhysAddr {
    /// Get the (floor) physical page number
    pub fn floor(&self) -> PhysPageNum {
        PhysPageNum(self.0 / PAGE_SIZE)
    }
    /// Get the (ceil) physical page number
    pub fn ceil(&self) -> PhysPageNum {
        PhysPageNum((self.0 - 1 + PAGE_SIZE) / PAGE_SIZE)
    }
    /// Get the page offset of physical address
    pub fn page_offset(&self) -> usize {
        self.0 & (PAGE_SIZE - 1)
    }
    /// Check if the physical address is aligned by page size
    pub fn aligned(&self) -> bool {
        self.page_offset() == 0
    }
}
impl From<PhysAddr> for PhysPageNum {
    fn from(v: PhysAddr) -> Self {
        assert_eq!(v.page_offset(), 0);
        v.floor()
    }
}
impl From<PhysPageNum> for PhysAddr {
    fn from(v: PhysPageNum) -> Self {
        Self(v.0 << PAGE_SIZE_BITS)
    }
}
impl VirtAddr {
    /// Get the mutable reference of virtual address
    pub fn get_mut<T>(&self) -> &'static mut T {
        unsafe { (self.0 as *mut T).as_mut().unwrap() }
    }
}

impl VirtPageNum {
    /// Get the indexes of the page table entry
    pub fn indexes(&self) -> [usize; PAGE_TABLE_LEVEL] {
        let mut vpn = self.0;
        let mut idx = [0usize; PAGE_TABLE_LEVEL];
        for i in (0..PAGE_TABLE_LEVEL).rev() {
            idx[i] = vpn & 511;
            vpn >>= 9;
        }
        idx
    }
    /// Get the mutable reference of virtual address
    pub fn get_mut<T>(&self) -> &'static mut T {
        let va: VirtAddr = (*self).into();
        va.get_mut()
    }
}

impl PhysAddr {
    /// Get the immutable reference of physical address
    pub fn get_ref<T>(&self) -> &'static T {
        unsafe { (self.0 as *const T).as_ref().unwrap() }
    }
    /// Get the mutable reference of physical address
    pub fn get_mut<T>(&self) -> &'static mut T {
        unsafe { (self.0 as *mut T).as_mut().unwrap() }
    }
}
impl PhysPageNum {
    /// Get the reference of page table(array of ptes)
    pub fn get_pte_array(&self) -> &'static mut [PageTableEntry] {
        let pa: PhysAddr = (*self).into();
        // debug!("get_pte_array: pa={:?}", pa);
        let kernel_pa = KernelAddr::from(pa).0;
        unsafe { core::slice::from_raw_parts_mut(kernel_pa as *mut PageTableEntry, 512) }
    }
    /// Get the reference of page(array of bytes)
    pub fn get_bytes_array(&self) -> &'static mut [u8] {
        let pa: PhysAddr = (*self).into();
        //debug!("get_bytes_array: pa={:?}", pa);
        let kernel_pa = KernelAddr::from(pa).0;
        unsafe { core::slice::from_raw_parts_mut(kernel_pa as *mut u8, 4096) }
    }
    /// Get the mutable reference of physical address
    pub fn get_mut<T>(&self) -> &'static mut T {
        let pa: PhysAddr = (*self).into();
        pa.get_mut()
    }
}

/// iterator for phy/virt page number
pub trait StepByOne {
    /// step by one element(page number)
    fn step(&mut self);
}
impl StepByOne for VirtPageNum {
    fn step(&mut self) {
        self.0 += 1;
    }
}
impl StepByOne for PhysPageNum {
    fn step(&mut self) {
        self.0 += 1;
    }
}

