/// Initialize trap handling
pub fn init() {
    set_kernel_trap_entry();
}
/// set trap entry for traps happen in kernel(supervisor) mode
fn set_kernel_trap_entry() {
    extern "C" {
        fn __trap_from_kernel();
    }
    unsafe {
        stvec::write(__trap_from_kernel as usize, TrapMode::Direct);
    }
}
/// set trap entry for traps happen in user mode
fn set_user_trap_entry() {
    extern "C" {
        fn __alltraps();
    }
    unsafe {
        stvec::write(__alltraps as usize, TrapMode::Direct);
    }
}

/// enable timer interrupt in supervisor mode
pub fn enable_timer_interrupt() {
    unsafe {
        sie::set_stimer();
    }
}

/// trap handler
#[no_mangle]
pub fn trap_handler() -> ! {
    set_kernel_trap_entry();
    let scause = scause::read();
    let stval = stval::read();
    let sepc = sepc::read();
    let call_trap_process_satp = satp::read().bits();
    let mut result = -1;
    info!(
        "[kernel] trap triggered, trap_handler: scause = {:?}, stval = {:#x}, sepc = {:#x}",
        scause.cause(),
        stval,
        sepc
    );
    let mut syscall_num = -1;
    // trace!("into {:?}", scause.cause());
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            //进入内核态之前，计算用户态已运行的时间
            current_task()
                .unwrap()
                .inner_exclusive_access(file!(), line!())
                .user_clock_time_end();

            // jump to next instruction anyway
            let mut cx = current_trap_cx();
            cx.sepc += 4;
            syscall_num = cx.x[17] as i32;
            // get system call return value
            debug!("syscall_num = {}", syscall_num);
            result = syscall(
                cx.x[17],
                [cx.x[10], cx.x[11], cx.x[12], cx.x[13], cx.x[14], cx.x[15]],
            );
            // // cx is changed during sys_exec, so we have to call it again
            // cx = current_trap_cx();
            // cx.x[10] = result as usize;
        }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            error!(
                "[kernel] trap_handler: {:?} in application, bad addr = {:#x}, bad instruction = \
                 {:#x}, kernel killed it.",
                scause.cause(),
                stval,
                current_trap_cx().sepc,
            );
            current_add_signal(SignalFlags::SIGSEGV);
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            exit_current_and_run_next(-1);
            current_add_signal(SignalFlags::SIGILL);
        }
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            set_next_trigger();
            check_timer();
            debug!("Interrupt::SupervisorTimer suspend_current_and_run_next");
            suspend_current_and_run_next();
            debug!("back from timer interrupt");
        }
        _ => {
            panic!(
                "[kernel] trap_handler: unsupport trap {:?} , bad addr = {:#x}, bad instruction = \
                 {:#x}",
                scause.cause(),
                stval,
                current_trap_cx().sepc,
            );
        }
    }
    //check signals
    if let Some((errno, msg)) = check_signals_of_current() {
        trace!("[kernel] trap_handler: .. check signals {}", msg);
        exit_current_and_run_next(errno);
    }

    let leave_trap_process_satp = satp::read().bits();

    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            if syscall_num == syscall::SYSCALL_EXECVE as i32 {
                // cx is changed during sys_exec, so we have to call it again
                let cx = current_trap_cx();
                cx.x[10] = result as usize;
                match current_task().unwrap().pid.0 {
                    0 => initproc_entry(),
                    _ => user_entry(),
                }
            } else {
                trace!("syscall {:?} finished, return to user space", syscall_num);
                if call_trap_process_satp != leave_trap_process_satp {
                    debug!(
                        "trap_handler: leave_trap_process = {:#x}, call_trap_process = {:#x}",
                        leave_trap_process_satp, call_trap_process_satp
                    );
                    match current_task().unwrap().pid.0 {
                        0 => initproc_entry(),
                        _ => user_entry(),
                    }
                } else {
                    // todo 不确定这样做对不对，最稳妥的做法是如果satp不同，就建立临时映射再写入这个返回值，但是我懒得写
                    let cx = current_trap_cx();
                    cx.x[10] = result as usize;
                    trap_return();
                }
            }
        }
        _ => {
            // 实际上这里只针对timer interrupt
            debug!(
                "trap_handler: leave_trap_process = {:#x}, call_trap_process = {:#x}",
                leave_trap_process_satp, call_trap_process_satp
            );
            if leave_trap_process_satp != call_trap_process_satp {
                match current_task().unwrap().pid.0 {
                    0 => initproc_entry(),
                    _ => user_entry(),
                }
            } else {
                trap_return();
            }
        }
    }
    panic!("[kernel] trap_handler: unreachable code");
}

